    }

    async fn complete_oauth(&self, _state: &str, _code: &str) -> Result<bool> {
        Ok(false)
    }

    fn pending_auth_url(&self) -> Option<String> {
        None
    }

    fn auth_state(&self) -> McpAuthState {
        McpAuthState::NotRequired
    }
}

